const body = $input.first().json.body || $input.first().json || {};
const clientId = body.client_id || body.client || 'godubai';

return {
  clientId: 'godubai',
  sessionId: body.session_id || ('sess_' + Date.now()),
  userMessage: body.user_message || '',
  messageHistory: Array.isArray(body.message_history) ? body.message_history : [],
  currentLead: body.current_lead || {},
  currentLeadCapture: body.current_lead_capture || {},
  lastProperties: Array.isArray(body.last_properties) ? body.last_properties : [],
  timestamp: new Date().toISOString()
};

const openaiRes = $input.first().json;
const ctx = $('Build Extraction Prompt').first().json;
function getOpenAIText(res) {
  if (typeof res.output_text === 'string') return res.output_text;
  if (Array.isArray(res.output)) return res.output.map(function(item) { return (item.content || []).map(function(c) { return c.text || ''; }).join(''); }).join('');
  if (Array.isArray(res.choices)) return res.choices.map(function(c) { return (c.message && c.message.content) || c.text || ''; }).join('');
  return '';
}
const tick3 = String.fromCharCode(96) + String.fromCharCode(96) + String.fromCharCode(96);
const text = getOpenAIText(openaiRes);
let raw = {};
try {
  const cleaned = text.replace(new RegExp(tick3 + 'json\\s*', 'gi'), '').replace(new RegExp(tick3 + '\\s*', 'g'), '').trim();
  raw = JSON.parse(cleaned);
} catch(e) { raw = { needs_property_search: false, search_reason: 'openai_json_parse_error_fallback' }; }
const cl = ctx.currentLead || {}; const clc = ctx.currentLeadCapture || {};
const criteria = {
  intent: (raw.intent != null && raw.intent !== '') ? raw.intent : (cl.intent || null),
  city: (raw.city != null && raw.city !== '') ? raw.city : (cl.city || null),
  area: (raw.area != null && raw.area !== '') ? raw.area : null,
  budget_max: (raw.budget_max != null && raw.budget_max > 0) ? raw.budget_max : (cl.budget || null),
  bedrooms_min: (raw.bedrooms_min != null && raw.bedrooms_min > 0) ? raw.bedrooms_min : (cl.bedrooms != null ? cl.bedrooms : null),
  timeline: (raw.timeline != null && raw.timeline !== '') ? raw.timeline : (cl.timeline || null),
  deal_type: (raw.deal_type != null && raw.deal_type !== '') ? raw.deal_type : null,
  needs_property_search: raw.needs_property_search === true,
  search_reason: raw.search_reason || ''
};
const name = (raw.customer_name != null && raw.customer_name !== '') ? raw.customer_name : (clc.name || null);
const phone = (raw.phone != null && raw.phone !== '') ? raw.phone : (clc.phone || null);
const email = (raw.email != null && raw.email !== '') ? raw.email : (clc.email || null);
const requested_action = (raw.requested_action != null && raw.requested_action !== '') ? raw.requested_action : (clc.requested_action || null);
const selected_property_reference = (raw.selected_property_reference != null && raw.selected_property_reference !== '') ? raw.selected_property_reference : (clc.selected_property_id || null);
const preferred_date_time = (raw.preferred_date_time != null && raw.preferred_date_time !== '') ? raw.preferred_date_time : (clc.preferred_date_time || null);
let capture_status = clc.capture_status || 'not_started';
if (requested_action === 'schedule_viewing' || requested_action === 'shortlist_request') {
  if (!name || (!phone && !email)) capture_status = 'waiting_for_contact';
  else if (!preferred_date_time && requested_action === 'schedule_viewing') capture_status = 'waiting_for_time';
  else capture_status = 'contact_captured';
} else if (requested_action === 'speak_to_agent' || requested_action === 'valuation_request' || requested_action === 'broker_leads_request') {
  if (!name || (!phone && !email)) capture_status = 'waiting_for_contact'; else capture_status = 'contact_captured';
} else if (name && (phone || email)) capture_status = 'contact_captured';
const hasContact = phone || email;
const isSeriousAction = requested_action === 'schedule_viewing' || requested_action === 'speak_to_agent' || requested_action === 'valuation_request' || requested_action === 'shortlist_request' || requested_action === 'broker_leads_request';
const should_save_lead = hasContact && isSeriousAction && clc.save_status !== 'saved';
return {
  criteria: criteria,
  leadCapture: { name: name, phone: phone, email: email, requested_action: requested_action, selected_property_id: selected_property_reference, preferred_date_time: preferred_date_time, capture_status: capture_status, should_save_lead: should_save_lead, save_status: clc.save_status || 'not_saved' },
  sessionId: ctx.sessionId, userMessage: ctx.userMessage, messageHistory: ctx.messageHistory, currentLead: ctx.currentLead, currentLeadCapture: ctx.currentLeadCapture, timestamp: ctx.timestamp, clientId: ctx.clientId, clientConfig: ctx.clientConfig
};

const rows = $input.all().map(function(i) { return i.json; });
const pd = $('Parse Extraction').first().json;
const c = pd.criteria;

function toNum(v) {
  if (v == null || v === '') return null;
  const x = parseFloat(String(v).replace(/[^0-9.-]/g, ''));
  return isNaN(x) ? null : x;
}

const filtered = rows.filter(function(r) {
  if (String(r.availability || '').toLowerCase().trim() !== 'available') return false;
  if (c.deal_type) {
    if (String(r.deal_type || '').toLowerCase().trim() !== c.deal_type.toLowerCase()) return false;
  }
  if (c.city) {
    const rc = String(r.city || '').toLowerCase();
    const cc = c.city.toLowerCase();
    if (!rc.includes(cc) && !cc.includes(rc)) return false;
  }
  if (c.area) {
    const ra = String(r.area || '').toLowerCase();
    if (!ra.includes(c.area.toLowerCase())) return false;
  }
  if (c.bedrooms_min != null) {
    const rb = toNum(r.bedrooms);
    if (rb == null || rb < Number(c.bedrooms_min)) return false;
  }
  if (c.budget_max != null) {
    const bgt = toNum(c.budget_max);
    if (bgt != null) {
      if (c.deal_type === 'rent') {
        const mp = toNum(r.price_per_month);
        if (mp != null && mp > bgt) return false;
      } else {
        const sp = toNum(r.price);
        if (sp != null && sp > bgt) return false;
      }
    }
  }
  return true;
});

const scored = filtered.map(function(r) {
  let s = 0;
  if (c.city && String(r.city || '').toLowerCase() === c.city.toLowerCase()) s += 10;
  if (c.area && String(r.area || '').toLowerCase().includes(c.area.toLowerCase())) s += 5;
  if (c.budget_max) {
    const bgt = toNum(c.budget_max);
    const price = c.deal_type === 'rent' ? toNum(r.price_per_month) : toNum(r.price);
    if (bgt && price != null && price <= bgt) s += Math.round((1 - price / bgt) * 5);
  }
  if (c.intent === 'invest') {
    const yld = toNum(r.investment_yield_pct);
    if (yld) s += Math.round(yld * 2);
  }
  return Object.assign({}, r, { _score: s });
});

const top3 = scored.sort(function(a, b) { return b._score - a._score; }).slice(0, 3);

const properties = top3.map(function(r) {
  return {
    property_id:          String(r.property_id || ''),
    title:                String(r.title || ''),
    deal_type:            String(r.deal_type || ''),
    city:                 String(r.city || ''),
    area:                 String(r.area || ''),
    price:                toNum(r.price),
    price_per_month:      toNum(r.price_per_month),
    currency:             String(r.currency || 'EUR'),
    bedrooms:             toNum(r.bedrooms) != null ? toNum(r.bedrooms) : 0,
    bathrooms:            toNum(r.bathrooms) != null ? toNum(r.bathrooms) : 0,
    size_sqm:             toNum(r.size_sqm) != null ? toNum(r.size_sqm) : 0,
    features:             String(r.features || ''),
    description:          String(r.description || ''),
    image_url:            String(r.image_url || ''),
    availability:         String(r.availability || ''),
    investment_yield_pct: toNum(r.investment_yield_pct)
  };
});

return {
  properties:      properties,
  propertiesFound: properties.length > 0,
  propertyCount:   properties.length,
  criteria:        pd.criteria,
  leadCapture:     pd.leadCapture,
  sessionId:       pd.sessionId,
  userMessage:     pd.userMessage,
  messageHistory:  pd.messageHistory,
  currentLead:     pd.currentLead,
  currentLeadCapture: pd.currentLeadCapture,
  timestamp:       pd.timestamp,
  clientId:        pd.clientId,
  clientConfig:    pd.clientConfig
};

