const openaiRes = $('OpenAI Generate Reply').first().json;
const md = $('Merge Paths').first().json;
const savedNodeResult = $('IF Should Save Lead').first().json;
const hasBeenSaved = savedNodeResult.conditions?.save_lead_check === true || md.leadCapture.save_status === 'saved';
function getOpenAIText(res) { if (typeof res.output_text === 'string') return res.output_text; if (Array.isArray(res.output)) return res.output.map(function(item) { return (item.content || []).map(function(c) { return c.text || ''; }).join(''); }).join(''); if (Array.isArray(res.choices)) return res.choices.map(function(c) { return (c.message && c.message.content) || c.text || ''; }).join(''); return ''; }
const reply = getOpenAIText(openaiRes).replace(/\[PROPERTY CONTEXT - START\][\s\S]*?\[PROPERTY CONTEXT - END\]/g, '').replace(/\[LAST SHOWN PROPERTIES CONTEXT - START\][\s\S]*?\[LAST SHOWN PROPERTIES CONTEXT - END\]/g, '').trim() || 'I apologize, I had a technical issue. Please try again.';
const cr = md.criteria || {}; const cl = md.currentLead || {}; const lc = md.leadCapture || {};
function calcScore(c, name, phone, email, action, time) { let s = 0; if (c.intent) s += 10; if (c.city) s += 10; if (c.budget_max) s += 10; if (c.bedrooms_min != null) s += 5; if (c.timeline) s += 10; if (name && (phone || email)) s += 30; if (action && action !== 'general_question') s += 15; if (time) s += 10; return Math.min(s, 100); }
const ls = calcScore(cr, lc.name, lc.phone, lc.email, lc.requested_action, lc.preferred_date_time); const lt = ls >= 70 ? 'hot' : ls >= 40 ? 'warm' : 'cold';
const lead = { intent: cr.intent || cl.intent || null, city: cr.city || cl.city || null, budget: cr.budget_max || cl.budget || null, bedrooms: cr.bedrooms_min != null ? cr.bedrooms_min : (cl.bedrooms != null ? cl.bedrooms : null), timeline: cr.timeline || cl.timeline || null, lead_score: ls, lead_tier: lt };
let finalCaptureStatus = lc.capture_status; let finalSaveStatus = lc.save_status; if (hasBeenSaved) { finalSaveStatus = 'saved'; finalCaptureStatus = 'notified'; }
const lead_capture = { name: lc.name, phone: lc.phone, email: lc.email, requested_action: lc.requested_action, selected_property_id: lc.selected_property_id, selected_property_title: lc.selected_property_title || (md.properties && md.properties.length > 0 ? md.properties[0].title : null), preferred_date_time: lc.preferred_date_time, capture_status: finalCaptureStatus, save_status: finalSaveStatus };
const ts = new Date().toISOString(); const evts = [];
if (cr.intent) evts.push({ type: 'intent_detected', label: 'Intent detected: ' + cr.intent.toUpperCase(), timestamp: ts });
if (cr.city) evts.push({ type: 'lead_updated', label: 'City qualified: ' + cr.city, timestamp: ts });
if (lc.requested_action === 'schedule_viewing') evts.push({ type: 'viewing_requested', label: 'Viewing request received', timestamp: ts });
if (lc.name && (lc.phone || lc.email)) evts.push({ type: 'contact_captured', label: 'Contact captured for ' + lc.name, timestamp: ts });
if (hasBeenSaved) { evts.push({ type: 'lead_saved', label: 'Lead details logged in Google Sheets (' + ((md.clientConfig && md.clientConfig.leadsSheet) || 'leads') + ')', timestamp: ts }); evts.push({ type: 'sales_alert_sent', label: 'Hot lead Telegram notification sent to ' + ((md.clientConfig && md.clientConfig.companyName) || 'sales'), timestamp: ts }); }
evts.push({ type: 'claude_response', label: ((md.clientConfig && md.clientConfig.assistantName) || 'Sofia') + ' response generated via OpenAI GPT-5.5', timestamp: ts });
return { session_id: md.sessionId || 'unknown', timestamp: md.timestamp || ts, reply: reply, lead: lead, lead_capture: lead_capture, properties: Array.isArray(md.properties) ? md.properties : [], system_events: evts };

const d = $input.first().json;

const clientConfig = {
  clientId: 'godubai',
  propertiesSheet: 'godubai_properties',
  leadsSheet: 'godubai_leads',
  companyName: 'GoDubai Portal',
  assistantName: 'Sofia',
  websiteUrl: 'https://www.godubai.estate/',
  market: 'Dubai & UAE',
  serviceAreas: ['Dubai', 'UAE', 'Business Bay', 'Dubai South', 'Dubai Design District (D3)', 'Jumeirah Village Circle (JVC)', 'Dubailand', 'Yas Island'],
  companyStrengths: [
    'verified Dubai and UAE off-plan project listings',
    'personalized Dubai investment plan flow',
    'support for brokers, investors, and property buyers',
    'human-verified exclusive real estate leads for brokers',
    'fast support and sales follow-up'
  ],
  telegramChatId: ''
};

return Object.assign({}, d, {
  clientId: 'godubai',
  clientConfig: clientConfig
});
